module top_module(
    input [7:0] d0, d1, d2, d3,
    input s0, s1,
    output [7:0] out
);wire [1:0] mux_sel;
assign mux_sel = {s1, s0};

assign out = (mux_sel == 2'b00) ? d0 :
             (mux_sel == 2'b01) ? d1 :
             (mux_sel == 2'b10) ? d2 :
             (mux_sel == 2'b11) ? d3 : 8'b0;

endmodule
